mapper.select:
select t1.cpu_usage as usageRate, t1.create_time from sys_actuator t1 where t1.del_flag = '0'
and t1.create_time between #{startTime} and #{endTime}
order by t1.create_time

select ROUND(t1.memery_used / t1.memery_max, 2) as usageRate, t1.create_time from sys_actuator t1 where t1.del_flag = '0'
and t1.create_time between #{startTime} and #{endTime}
order by t1.create_time
